const d = $input.first().json.body;
const rows = (d.missing_drawings || []).map(p => {
  const typeLabel = p.type === 'sheet_metal' ? 'Sheet Metal (290-)' : p.type === 'machining' ? 'Machining (300-)' : p.type || '-';
  return `<tr><td style="padding:6px 10px;border:1px solid #ddd;font-family:monospace">${p.part_no}</td><td style="padding:6px 10px;border:1px solid #ddd">${p.description || '-'}</td><td style="padding:6px 10px;border:1px solid #ddd;text-align:center">${p.qty}</td><td style="padding:6px 10px;border:1px solid #ddd">${typeLabel}</td></tr>`;
}).join('');
const emailHtml = `<div style="font-family:Arial,sans-serif;max-width:680px"><h2 style="color:#c0392b">&#9888; Missing Drawing Alert</h2><p>Project <strong>${d.project}</strong> is missing <strong>${d.missing_count}</strong> fabrication drawing(s).</p><table style="border-collapse:collapse;width:100%"><thead><tr style="background:#f2f2f2"><th style="padding:8px 10px;border:1px solid #ddd;text-align:left">Part No</th><th style="padding:8px 10px;border:1px solid #ddd;text-align:left">Description</th><th style="padding:8px 10px;border:1px solid #ddd;text-align:center">Qty</th><th style="padding:8px 10px;border:1px solid #ddd;text-align:left">Type</th></tr></thead><tbody>${rows}</tbody></table><p style="margin-top:20px"><strong>Total fabrication parts:</strong> ${d.total_fabrication_parts}<br><strong>Present:</strong> ${d.total_fabrication_parts - d.missing_count}<br><strong>Missing:</strong> ${d.missing_count}</p><p style="color:#888;font-size:12px">Checked: ${d.timestamp}<br>Folder: ${d.folder}</p><p>Please upload the missing drawings to Google Drive.</p></div>`;
return [{ json: { ...d, emailHtml, emailSubject: `[MISSING DRAWINGS] ${d.project} – ${d.missing_count} drawing(s) missing` } }];
